import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [schemes, setSchemes] = useState([]);
  const [filteredSchemes, setFilteredSchemes] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedState, setSelectedState] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    fetchSchemes();
  }, []);

  useEffect(() => {
    filterSchemes();
  }, [schemes, searchQuery, selectedCategory, selectedState]);

  const fetchSchemes = async () => {
    setIsLoading(true);
    try {
      const response = await axios.get('/api/schemes');
      setSchemes(response.data);
    } catch (error) {
      console.error('Error fetching schemes:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const filterSchemes = () => {
    let filtered = schemes;

    if (searchQuery) {
      filtered = filtered.filter(scheme =>
        scheme.scheme_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        scheme.summary.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    if (selectedCategory) {
      filtered = filtered.filter(scheme => scheme.category === selectedCategory);
    }

    if (selectedState) {
      filtered = filtered.filter(scheme => scheme.state === selectedState);
    }

    setFilteredSchemes(filtered);
  };

  const categories = [...new Set(schemes.map(s => s.category))];
  const states = [...new Set(schemes.map(s => s.state))];

  return (
    <div className="app">
      {/* Top Navigation */}
      <nav className="top-nav">
        <div className="nav-banner">Government of India Initiative</div>
        <div className="nav-main">
          <div className="nav-brand">
            <div className="nav-emblem">🇮🇳</div>
            <div className="nav-title">
              <h1>YojanaAI</h1>
              <p>Government Scheme Finder</p>
            </div>
          </div>
          <div className="nav-links">
            <span className="nav-tag">AI-Powered</span>
            <span className="nav-ai-badge">Fraud Protected</span>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="hero-section">
        <h1 className="hero-title">Find Every Government Scheme You Deserve</h1>
        <p className="hero-sub">In your language, instantly, with AI fraud protection.</p>
        <div className="hero-stats">
          <div className="stat-pill">
            <span>{schemes.length}</span> Schemes Available
          </div>
          <div className="stat-pill">
            <span>AI</span> Fraud Detection
          </div>
          <div className="stat-pill">
            <span>Multi</span> Language Support
          </div>
        </div>
      </section>

      {/* Search and Filters */}
      <div className="search-section">
        <div className="search-container">
          <div className="search-bar">
            <input
              type="text"
              placeholder="Search schemes..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            <button onClick={filterSchemes}>🔍 Search</button>
          </div>
          <div className="filters">
            <select value={selectedCategory} onChange={(e) => setSelectedCategory(e.target.value)}>
              <option value="">All Categories</option>
              {categories.map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
            <select value={selectedState} onChange={(e) => setSelectedState(e.target.value)}>
              <option value="">All States</option>
              {states.map(state => (
                <option key={state} value={state}>{state}</option>
              ))}
            </select>
            <button className="voice-btn">🎤 Voice Search</button>
          </div>
        </div>
      </div>

      {/* Schemes Grid */}
      <main className="schemes-section">
        {isLoading ? (
          <div className="loading">Loading schemes...</div>
        ) : (
          <div className="schemes-grid">
            {filteredSchemes.map((scheme) => (
              <div key={scheme._id} className="scheme-card">
                <div className="card-header">
                  <span className="card-category-badge">{scheme.category}</span>
                  <h3 className="card-title">{scheme.scheme_name}</h3>
                </div>
                <div className="card-body">
                  <p className="card-summary">{scheme.summary}</p>
                  <div className="card-meta">
                    <span className="meta-tag">{scheme.state}</span>
                    <span className="meta-tag">{scheme.income_level}</span>
                  </div>
                  <div className="eligibility-bar-wrap">
                    <div className="elig-label">Eligibility Match</div>
                    <div className="elig-bar-bg">
                      <div className="elig-bar-fill" style={{width: '75%'}}></div>
                    </div>
                  </div>
                  <a href={scheme.application_link} className="btn-check" target="_blank" rel="noopener noreferrer">
                    Check Eligibility
                  </a>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
